  const aiResponse = JSON.parse($json.choices[0].message.content);

  return [{
    json: {
      ...$('Loop Over Items').item.json,
      subject: aiResponse.subject || "Quick hello",
      body: aiResponse.body || "No body"
    }
  }];

} catch (e) {

  return [{
    json: {
      ...$('Loop Over Items').item.json,
      subject: "Quick hello",
